import{bQ as e,aL as d,u as a,G as r}from"./chunks/framework.D06dwy5q.js";const A=JSON.parse('{"title":"负载均衡","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/08-负载均衡.md","filePath":"00.互联网与架构基础/08-负载均衡.md","lastUpdated":null}'),o={name:"00.互联网与架构基础/08-负载均衡.md"};function c(h,t,s,i,p,l){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="负载均衡" tabindex="-1">负载均衡 <a class="header-anchor" href="#负载均衡" aria-label="Permalink to &quot;负载均衡&quot;">​</a></h1><p>一个服务只有一个实例时，请求直接打过去就行。服务变成多个实例以后，浏览器或客户端总不能自己记住每台机器的地址。负载均衡就是放在前面的入口：用户访问它，它再把请求分给后面的实例。</p><p>负载均衡解决的不只是“分摊压力”。它还让应用可以扩容、下线、滚动发布。某个后端挂了，入口层可以把它摘掉，用户继续访问其他健康实例。</p><h2 id="一、一个入口-多台后端" tabindex="-1">一、一个入口，多台后端 <a class="header-anchor" href="#一、一个入口-多台后端" aria-label="Permalink to &quot;一、一个入口，多台后端&quot;">​</a></h2><p>最常见的形态是用户访问一个固定入口，后面挂多个应用实例。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20Web1%5B%22Web%201%22%5D%0A%20%20Web2%5B%22Web%202%22%5D%0A%20%20Web3%5B%22Web%203%22%5D%0A%0A%20%20User%20--%3E%20LB%0A%20%20LB%20--%3E%20Web1%0A%20%20LB%20--%3E%20Web2%0A%20%20LB%20--%3E%20Web3%0A"></div><p>用户只记住负载均衡的域名或 IP。后端新增、重启、下线，入口地址不变。</p><h2 id="二、dns-也能分流" tabindex="-1">二、DNS 也能分流 <a class="header-anchor" href="#二、dns-也能分流" aria-label="Permalink to &quot;二、DNS 也能分流&quot;">​</a></h2><p>最简单的分流方式是 DNS 返回多个 IP。例如 <code>www.example.com</code> 同时返回三台服务器地址：</p><table tabindex="0"><thead><tr><th>域名</th><th>IP</th></tr></thead><tbody><tr><td><code>www.example.com</code></td><td><code>203.0.113.10</code></td></tr><tr><td><code>www.example.com</code></td><td><code>203.0.113.11</code></td></tr><tr><td><code>www.example.com</code></td><td><code>203.0.113.12</code></td></tr></tbody></table><p>这样不同客户端可能拿到不同 IP。实现很简单，但健康检查不够细。某台服务器已经坏了，如果 DNS 还返回它的 IP，部分用户仍然会失败。TTL 缓存也会让切换没那么及时。</p><p>DNS 更适合做地域调度、线路调度或入口层前置选择。具体实例健康和请求分发，通常交给负载均衡设备、云负载均衡、Nginx、HAProxy、Ingress 这类组件。</p><h2 id="三、四层和七层" tabindex="-1">三、四层和七层 <a class="header-anchor" href="#三、四层和七层" aria-label="Permalink to &quot;三、四层和七层&quot;">​</a></h2><p>负载均衡常分成四层和七层。这个名字来自网络分层，可以先按“看不看得懂 HTTP”来理解。</p><table tabindex="0"><thead><tr><th>类型</th><th>它能看到什么</th><th>常见能力</th></tr></thead><tbody><tr><td>四层负载均衡</td><td>IP、端口、TCP/UDP 连接</td><td>转发性能高，适合通用 TCP 服务</td></tr><tr><td>七层负载均衡</td><td>HTTP 域名、路径、Header、Cookie</td><td>按域名和路径转发，适合 Web 和 API</td></tr></tbody></table><p>四层负载均衡关心 <code>IP:Port</code>。七层负载均衡能读懂 HTTP，可以把 <code>api.example.com</code> 转到 API 服务，把 <code>/static</code> 转到静态资源服务。</p><p>Kubernetes 里的 Ingress、Gateway API 多数属于七层入口。LVS、云厂商 TCP 负载均衡更接近四层。</p><h2 id="四、健康检查" tabindex="-1">四、健康检查 <a class="header-anchor" href="#四、健康检查" aria-label="Permalink to &quot;四、健康检查&quot;">​</a></h2><p>负载均衡要知道后端实例能不能用。健康检查就是定期探测后端，失败次数达到阈值后把实例摘掉，恢复后再加回来。</p><p>常见检查方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td>TCP 检查</td><td>端口能建立连接就算健康</td></tr><tr><td>HTTP 检查</td><td>请求 <code>/health</code> 这类路径，状态码符合预期才算健康</td></tr><tr><td>自定义检查</td><td>结合业务依赖或内部状态</td></tr></tbody></table><p>TCP 检查只能说明端口还开着。应用线程池打满、数据库不可用时，端口可能仍然能连接，但业务已经处理不了请求。HTTP 健康检查更接近应用状态，但检查路径要轻量，频繁检查不适合每次都打到数据库查一堆数据。</p><p>健康检查失败时，用户侧可能看到部分请求 502 或 503。负载均衡日志里某个后端连续 <code>unhealthy</code>，后端应用日志又没有收到请求，问题更接近入口到后端这一段。</p><h2 id="五、反向代理" tabindex="-1">五、反向代理 <a class="header-anchor" href="#五、反向代理" aria-label="Permalink to &quot;五、反向代理&quot;">​</a></h2><p>Nginx 和 HAProxy 常用作反向代理。反向代理对外接收请求，对内转发给后端服务。客户端看到的是代理地址，不直接感知后端实例。</p><p>反向代理常做这些事：</p><table tabindex="0"><thead><tr><th>能力</th><th>作用</th></tr></thead><tbody><tr><td>域名转发</td><td>不同 Host 转到不同服务</td></tr><tr><td>路径转发</td><td><code>/api</code> 转后端，<code>/static</code> 返回静态资源</td></tr><tr><td>TLS 终止</td><td>在代理层处理 HTTPS 证书</td></tr><tr><td>限流</td><td>控制请求速率</td></tr><tr><td>日志</td><td>记录来源、状态码、耗时</td></tr></tbody></table><p>反向代理日志很有用。<code>status=502 upstream_status=502</code> 表示后端链路失败；<code>request_time=5.2 upstream_response_time=5.1</code> 表示主要时间耗在后端。</p><h2 id="六、入口层会变长" tabindex="-1">六、入口层会变长 <a class="header-anchor" href="#六、入口层会变长" aria-label="Permalink to &quot;六、入口层会变长&quot;">​</a></h2><p>成熟系统的入口层可能不止一个负载均衡。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20CDN%5B%22CDN%22%5D%0A%20%20WAF%5B%22WAF%22%5D%0A%20%20SLB%5B%22%E4%BA%91%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20Ingress%5B%22Ingress%20%2F%20Gateway%22%5D%0A%20%20Service%5B%22%E4%B8%9A%E5%8A%A1%E6%9C%8D%E5%8A%A1%22%5D%0A%0A%20%20User%20--%3E%20CDN%0A%20%20CDN%20--%3E%20WAF%0A%20%20WAF%20--%3E%20SLB%0A%20%20SLB%20--%3E%20Ingress%0A%20%20Ingress%20--%3E%20Service%0A"></div><p>每一层都可能返回自己的状态码、日志和错误页。排查入口问题时，先确认请求停在哪一层，比只看浏览器报错更有用。</p><p>负载均衡把多个实例收在一个入口后面。扩容、摘除、发布和故障切换，都要靠它把流量分得清楚。</p>',33)])])}const b=e(o,[["render",c]]);export{A as __pageData,b as default};
